import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import './AdminPanel.css';

export default function AdminPanel() {
  const { user, logout } = useAuth();
  const [users, setUsers] = useState([]);
  const [form, setForm] = useState({ name: '', email: '', password: '', role: 'auditor' });
  const [msg, setMsg] = useState({ text: '', type: '' });
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);
  const [tab, setTab] = useState('users');

  const fetchUsers = async () => {
    try {
      const res = await axios.get('/api/admin/users');
      setUsers(res.data);
    } catch (e) {
      console.error(e);
    } finally {
      setFetching(false);
    }
  };

  useEffect(() => { fetchUsers(); }, []);

  const showMsg = (text, type = 'success') => {
    setMsg({ text, type });
    setTimeout(() => setMsg({ text: '', type: '' }), 3000);
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post('/api/admin/create-user', form);
      showMsg(`User "${form.name}" created successfully!`);
      setForm({ name: '', email: '', password: '', role: 'auditor' });
      fetchUsers();
      setTab('users');
    } catch (err) {
      showMsg(err.response?.data?.message || 'Error creating user', 'error');
    } finally {
      setLoading(false);
    }
  };

  const handleDeactivate = async (id, name) => {
    if (!window.confirm(`Deactivate "${name}"?`)) return;
    try {
      await axios.delete(`/api/admin/users/${id}`);
      showMsg(`"${name}" deactivated`);
      fetchUsers();
    } catch (e) {
      showMsg('Error deactivating user', 'error');
    }
  };

  return (
    <div className="ap-bg">
      <div className="ap-header">
        <div className="ap-logo">AuditPro</div>
        <div className="ap-header-right">
          <span className="ap-welcome">👋 {user?.name}</span>
          <span className="ap-role-tag">Admin</span>
          <button onClick={logout} className="ap-logout">Logout</button>
        </div>
      </div>

      <div className="ap-main">
        <div className="ap-sidebar">
          <div className="ap-sidebar-title">Admin Panel</div>
          <nav>
            <button className={`ap-nav-btn ${tab === 'users' ? 'active' : ''}`} onClick={() => setTab('users')}>
              <span>👥</span> All Users
              <span className="ap-count">{users.length}</span>
            </button>
            <button className={`ap-nav-btn ${tab === 'create' ? 'active' : ''}`} onClick={() => setTab('create')}>
              <span>➕</span> Create User
            </button>
          </nav>
        </div>

        <div className="ap-content">
          {msg.text && (
            <div className={`ap-msg ${msg.type}`}>{msg.type === 'error' ? '⚠' : '✓'} {msg.text}</div>
          )}

          {tab === 'users' && (
            <div className="ap-section">
              <h2>All Users</h2>
              {fetching ? (
                <div className="ap-loading">Loading...</div>
              ) : users.length === 0 ? (
                <div className="ap-empty">No users yet. Create one!</div>
              ) : (
                <div className="ap-table-wrap">
                  <table className="ap-table">
                    <thead>
                      <tr>
                        <th>Name</th>
                        <th>Email</th>
                        <th>Role</th>
                        <th>Status</th>
                        <th>Action</th>
                      </tr>
                    </thead>
                    <tbody>
                      {users.map(u => (
                        <tr key={u._id}>
                          <td><div className="ap-name-cell"><div className="ap-avatar">{u.name[0]}</div>{u.name}</div></td>
                          <td className="ap-email">{u.email}</td>
                          <td><span className={`ap-badge ${u.role}`}>{u.role}</span></td>
                          <td><span className={`ap-status ${u.isActive ? 'active' : 'inactive'}`}>{u.isActive ? 'Active' : 'Inactive'}</span></td>
                          <td>
                            {u.isActive && u._id !== user?.id && (
                              <button className="ap-deactivate-btn" onClick={() => handleDeactivate(u._id, u.name)}>
                                Deactivate
                              </button>
                            )}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}

          {tab === 'create' && (
            <div className="ap-section">
              <h2>Create New User</h2>
              <form onSubmit={handleCreate} className="ap-form">
                <div className="ap-form-grid">
                  <div className="ap-field">
                    <label>Full Name</label>
                    <input type="text" placeholder="John Doe" value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} required />
                  </div>
                  <div className="ap-field">
                    <label>Email Address</label>
                    <input type="email" placeholder="john@company.com" value={form.email} onChange={e => setForm(f => ({ ...f, email: e.target.value }))} required />
                  </div>
                  <div className="ap-field">
                    <label>Password</label>
                    <input type="password" placeholder="Min 6 characters" value={form.password} onChange={e => setForm(f => ({ ...f, password: e.target.value }))} required />
                  </div>
                  <div className="ap-field">
                    <label>Role</label>
                    <select value={form.role} onChange={e => setForm(f => ({ ...f, role: e.target.value }))}>
                      <option value="auditor">Auditor</option>
                      <option value="admin">Admin</option>
                    </select>
                  </div>
                </div>
                <button type="submit" className="ap-create-btn" disabled={loading}>
                  {loading ? <span className="spinner"></span> : '+ Create User'}
                </button>
              </form>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
